create table dirkspzm32.isi_res_schicht_modell (
    schicht_modell_id          number(*, 0) not null enable,
    parent_id                  number(*, 0) not null enable,
    sid                        varchar2(2 char) not null enable,
    firma_nr                   number(*, 0) not null enable,
    schicht_modell_type        varchar2(1 char) default 'S' not null enable,
    schicht_modell_name        varchar2(40 char) not null enable,
    start_time                 date not null enable,
    ende_time                  date not null enable,
    abzug_produktions_zeit_sek number(*, 0) default 0 not null enable,
    prod_takt_id               number(*, 0),
    takt_zeit_sek              number(*, 0) default 1 not null enable,
    wochen_tage                varchar2(30 char) default 'Mo;Di;Mi;Do;Fr;' not null enable,
    created_date               date default sysdate,
    created_login_id           number(*, 0) default - 1,
    last_change_date           date,
    last_change_login_id       number(*, 0),
    takte_pro_schicht          number(*, 0) default 1 not null enable,
    stk_pro_schicht            number(*, 0),
    schicht_ende_variabel      varchar2(1 char) default 'F'
);

alter table dirkspzm32.isi_res_schicht_modell
    add constraint chk_schicht_modell_ende_var
        check ( schicht_ende_variabel in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.isi_res_schicht_modell
    add constraint chk_schicht_modell_type
        check ( schicht_modell_type in ( 'S', 'P' ) ) enable;

alter table dirkspzm32.isi_res_schicht_modell
    add constraint pk_schicht_modell_id primary key ( schicht_modell_id )
        using index enable;


